def find_all(text, pattern):
    """KMP (Knuth-Morris-Pratt) string matching algorithm."""
    n = len(text)
    m = len(pattern)
    if m == 0:
        return []
    # Build failure function
    fail = [0] * m
    j = 0
    for i in range(1, m):
        while j > 0 and pattern[j] != pattern[i]:
            j = fail[j - 1]
        if pattern[j] == pattern[i]:
            j += 1
        fail[i] = j
    # Search
    result = []
    j = 0
    for i in range(n):
        while j > 0 and pattern[j] != text[i]:
            j = fail[j - 1]
        if pattern[j] == text[i]:
            j += 1
        if j == m:
            result.append(i - m + 1)
            j = fail[j - 1]
    return result

def find_all(text, pattern):
    """Rabin-Karp with rolling hash."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    base = 256
    mod = 1000000007
    result = []
    # Compute hash of pattern and first window
    p_hash = 0
    t_hash = 0
    h = 1
    for i in range(m - 1):
        h = (h * base) % mod
    for i in range(m):
        p_hash = (base * p_hash + ord(pattern[i])) % mod
        t_hash = (base * t_hash + ord(text[i])) % mod
    for i in range(n - m + 1):
        if p_hash == t_hash:
            # Verify character by character
            match = True
            for j in range(m):
                if text[i + j] != pattern[j]:
                    match = False
                    break
            if match:
                result.append(i)
        if i < n - m:
            t_hash = (base * (t_hash - ord(text[i]) * h) + ord(text[i + m])) % mod
            if t_hash < 0:
                t_hash += mod
    return result

def find_all(text, pattern):
    """Boyer-Moore-Horspool algorithm."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    # Build bad character shift table
    shift = {}
    for i in range(m - 1):
        shift[pattern[i]] = m - 1 - i
    default_shift = m
    result = []
    i = 0
    while i <= n - m:
        j = m - 1
        while j >= 0 and text[i + j] == pattern[j]:
            j -= 1
        if j < 0:
            result.append(i)
            i += 1
        else:
            i += shift.get(text[i + m - 1], default_shift)
    return result

def find_all(text, pattern):
    """Z-algorithm based string matching."""
    m = len(pattern)
    n = len(text)
    if m == 0 or m > n:
        return []
    concat = pattern + '$' + text
    total = len(concat)
    z = [0] * total
    z[0] = total
    l, r = 0, 0
    for i in range(1, total):
        if i < r:
            z[i] = min(r - i, z[i - l])
        while i + z[i] < total and concat[z[i]] == concat[i + z[i]]:
            z[i] += 1
        if i + z[i] > r:
            l, r = i, i + z[i]
    result = []
    for i in range(m + 1, total):
        if z[i] == m:
            result.append(i - m - 1)
    return result

def find_all(text, pattern):
    """Two-way string matching algorithm (simplified)."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    result = []
    # Compute maximal suffix
    def max_suffix(p, order):
        ms = -1
        j = 0
        k = 1
        period = 1
        length = len(p)
        while j + k < length:
            a = p[j + k]
            b = p[ms + k]
            if (order and a < b) or (not order and a > b):
                j += k
                k = 1
                period = j - ms
            elif a == b:
                if k == period:
                    j += period
                    k = 1
                else:
                    k += 1
            else:
                ms = j
                j = ms + 1
                k = 1
                period = 1
        return ms, period
    ms1, p1 = max_suffix(pattern, True)
    ms2, p2 = max_suffix(pattern, False)
    if ms1 >= ms2:
        ms, period = ms1, p1
    else:
        ms, period = ms2, p2
    # Search phase
    i = 0
    memory = 0
    split = ms + 1
    if pattern[:split] == pattern[period:period + split]:
        while i <= n - m:
            j = max(split, memory)
            while j < m and text[i + j] == pattern[j]:
                j += 1
            if j < m:
                i += max(1, j - ms)
                memory = 0
            else:
                j = split - 1
                while j >= memory and text[i + j] == pattern[j]:
                    j -= 1
                if j < memory:
                    result.append(i)
                i += period
                memory = m - period
    else:
        while i <= n - m:
            j = split
            while j < m and text[i + j] == pattern[j]:
                j += 1
            if j < m:
                i += max(1, j - ms)
            else:
                j = split - 1
                while j >= 0 and text[i + j] == pattern[j]:
                    j -= 1
                if j < 0:
                    result.append(i)
                i += max(1, split - j)
    return result

def find_all(text, pattern):
    """Bitap (shift-or) algorithm for exact matching."""
    n = len(text)
    m = len(pattern)
    if m == 0 or m > n:
        return []
    if m > 63:
        # Fall back to naive for very long patterns
        result = []
        for i in range(n - m + 1):
            match = True
            for j in range(m):
                if text[i + j] != pattern[j]:
                    match = False
                    break
            if match:
                result.append(i)
        return result
    # Build character masks
    char_mask = {}
    for i in range(m):
        c = pattern[i]
        if c not in char_mask:
            char_mask[c] = ~0
        char_mask[c] &= ~(1 << i)
    result = []
    state = ~0
    match_bit = 1 << (m - 1)
    for i in range(n):
        state = (state << 1) | char_mask.get(text[i], ~0)
        if not (state & match_bit):
            result.append(i - m + 1)
    return result
